<template>
  <div class="app-wrapper">
    <FacultySidebar />
    
    <div class="main-content">
      <TopNav :pageTitle="'Faculty Dashboard'" />
      
      <div class="container-fluid p-4">
        <!-- Debug Info (remove in production) -->
        <div v-if="showDebug" class="alert alert-secondary mb-3">
          <div class="d-flex justify-content-between align-items-center">
            <strong>Debug Info:</strong>
            <button class="btn btn-sm btn-outline-secondary" @click="testApiConnection">
              <i class="bi bi-plug"></i> Test API
            </button>
          </div>
          <pre class="mb-0 mt-2">{{ debugInfo }}</pre>
        </div>

        <!-- Loading State -->
        <div v-if="loading" class="text-center py-5">
          <div class="spinner-border text-primary" style="width: 3rem; height: 3rem;" role="status">
            <span class="visually-hidden">Loading...</span>
          </div>
          <p class="mt-3 text-muted">Loading dashboard data...</p>
        </div>

        <!-- Error State with Retry -->
        <div v-else-if="error" class="error-container text-center py-5">
          <div class="error-icon mb-4">
            <i class="bi bi-exclamation-triangle-fill text-danger" style="font-size: 4rem;"></i>
          </div>
          <h4 class="text-danger mb-3">Oops! Something went wrong</h4>
          <p class="text-muted mb-4">{{ error }}</p>
          <div class="d-flex gap-2 justify-content-center">
            <button class="btn btn-primary" @click="fetchDashboardData">
              <i class="bi bi-arrow-clockwise me-2"></i>Retry
            </button>
            <button class="btn btn-outline-secondary" @click="showDebug = !showDebug">
              <i class="bi bi-bug me-2"></i>Toggle Debug
            </button>
          </div>
        </div>

        <!-- Dashboard Content -->
        <template v-else>
          <!-- Welcome Banner -->
          <div class="welcome-banner mb-4">
            <div class="d-flex flex-wrap align-items-center justify-content-between">
              <div class="d-flex align-items-center">
                <div class="welcome-avatar me-3">
                  <div class="avatar-circle bg-primary text-white">
                    {{ facultyName.charAt(0) }}
                  </div>
                </div>
                <div>
                  <h4 class="mb-1">Welcome back, {{ facultyName }}!</h4>
                  <p class="mb-0 text-white-50">
                    <i class="bi bi-briefcase me-2"></i>{{ faculty.designation || 'Faculty' }} • 
                    <i class="bi bi-building me-2"></i>{{ faculty.department || 'Department' }}
                  </p>
                </div>
              </div>
              <div class="welcome-date mt-2 mt-sm-0">
                <div class="date-badge">
                  <i class="bi bi-calendar3 me-2"></i>
                  {{ currentDate }}
                </div>
              </div>
            </div>
          </div>
          
          <!-- Statistics Cards -->
          <div class="row g-4 mb-4">
            <div v-for="stat in statistics" :key="stat.label" class="col-sm-6 col-lg-3">
              <div class="stat-card h-100">
                <div class="d-flex align-items-center">
                  <div class="stat-icon-wrapper" :style="{ background: stat.color + '15' }">
                    <i :class="stat.icon" :style="{ color: stat.color }"></i>
                  </div>
                  <div class="ms-3 flex-grow-1">
                    <h3 class="stat-value mb-1">{{ stat.value }}</h3>
                    <p class="stat-label mb-0">{{ stat.label }}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
          
          <div class="row">
            <!-- Today's Schedule -->
            <div class="col-lg-6 mb-4">
              <div class="dashboard-card h-100">
                <div class="card-header d-flex justify-content-between align-items-center">
                  <div class="d-flex align-items-center">
                    <div class="header-icon me-3">
                      <i class="bi bi-calendar-day text-primary"></i>
                    </div>
                    <h5 class="mb-0">Today's Classes</h5>
                    <span class="badge bg-primary ms-2">{{ todayClasses.length }}</span>
                  </div>
                  <router-link to="/faculty/schedule" class="btn btn-sm btn-outline-primary">
                    <i class="bi bi-arrow-right me-1"></i>View All
                  </router-link>
                </div>
                
                <div class="card-body p-0">
                  <div v-if="todayClasses.length === 0" class="empty-state p-5 text-center">
                    <i class="bi bi-calendar-x" style="font-size: 3rem; color: #dee2e6;"></i>
                    <p class="text-muted mt-3 mb-0">No classes scheduled for today</p>
                    <p class="text-muted small">Enjoy your day off!</p>
                  </div>
                  
                  <div v-else class="class-list">
                    <div v-for="classItem in todayClasses" :key="classItem.id" 
                         class="class-item p-3 border-bottom">
                      <div class="d-flex align-items-center">
                        <div class="class-time me-3 text-center">
                          <div class="time-badge bg-light rounded p-2" style="min-width: 80px;">
                            <div class="small text-muted">Start</div>
                            <strong>{{ formatTime(classItem.time_start) }}</strong>
                            <div class="small text-muted mt-1">End</div>
                            <strong>{{ formatTime(classItem.time_end) }}</strong>
                          </div>
                        </div>
                        <div class="class-info flex-grow-1">
                          <h6 class="mb-2">{{ classItem.course_code }} - {{ classItem.course_name }}</h6>
                          <div class="d-flex flex-wrap gap-3 small">
                            <span class="text-muted">
                              <i class="bi bi-people me-1"></i>{{ classItem.section_code }}
                            </span>
                            <span class="text-muted">
                              <i class="bi bi-door-open me-1"></i>{{ classItem.room_code }}
                            </span>
                            <span class="text-muted">
                              <i class="bi bi-person-check me-1"></i>{{ classItem.student_count || 0 }} students
                            </span>
                          </div>
                        </div>
                        <span class="class-status-badge ms-3" 
                              :class="getClassStatus(classItem.time_start, classItem.time_end)">
                          {{ getClassStatusText(classItem.time_start, classItem.time_end) }}
                        </span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
            
            <!-- Upcoming Events -->
            <div class="col-lg-6 mb-4">
              <div class="dashboard-card h-100">
                <div class="card-header d-flex justify-content-between align-items-center">
                  <div class="d-flex align-items-center">
                    <div class="header-icon me-3">
                      <i class="bi bi-calendar-event text-success"></i>
                    </div>
                    <h5 class="mb-0">Upcoming Events</h5>
                    <span class="badge bg-success ms-2">{{ upcomingEvents.length }}</span>
                  </div>
                  <router-link to="/faculty/events" class="btn btn-sm btn-outline-success">
                    <i class="bi bi-arrow-right me-1"></i>View All
                  </router-link>
                </div>
                
                <div class="card-body p-0">
                  <div v-if="upcomingEvents.length === 0" class="empty-state p-5 text-center">
                    <i class="bi bi-calendar2-x" style="font-size: 3rem; color: #dee2e6;"></i>
                    <p class="text-muted mt-3 mb-0">No upcoming events</p>
                    <p class="text-muted small">Check back later for events</p>
                  </div>
                  
                  <div v-else class="events-list">
                    <div v-for="event in upcomingEvents" :key="event.id" 
                         class="event-item p-3 border-bottom">
                      <div class="d-flex">
                        <!-- Event Date Badge -->
                        <div class="event-date me-3 text-center">
                          <div class="date-badge bg-light rounded p-2" style="min-width: 70px;">
                            <div class="small text-muted">{{ formatEventMonth(event.event_date) }}</div>
                            <strong class="fs-5">{{ formatEventDay(event.event_date) }}</strong>
                          </div>
                        </div>
                        
                        <!-- Event Details -->
                        <div class="event-info flex-grow-1">
                          <div class="d-flex justify-content-between align-items-start">
                            <h6 class="mb-1">{{ event.title }}</h6>
                            <span class="event-type-badge" :class="getEventTypeClass(event.event_type)">
                              {{ event.event_type }}
                            </span>
                          </div>
                          <p class="text-muted small mb-2">{{ event.description }}</p>
                          <div class="d-flex flex-wrap gap-3 small">
                            <span class="text-muted" v-if="event.event_time">
                              <i class="bi bi-clock me-1"></i>{{ formatEventTime(event.event_time) }}
                            </span>
                            <span class="text-muted" v-if="event.venue">
                              <i class="bi bi-geo-alt me-1"></i>{{ event.venue }}
                            </span>
                            <span class="text-muted" v-if="event.organizer">
                              <i class="bi bi-person me-1"></i>{{ event.organizer }}
                            </span>
                          </div>
                          
                          <!-- Days remaining badge and created by -->
                          <div class="mt-2 d-flex flex-wrap align-items-center gap-2">
                            <span class="days-remaining-badge" :class="getDaysRemainingClass(event.event_date)">
                              <i class="bi bi-hourglass-split me-1"></i>
                              {{ getDaysRemaining(event.event_date) }}
                            </span>
                            <span class="small text-muted" v-if="event.created_by_name">
                              <i class="bi bi-person-plus me-1"></i>Created by: {{ event.created_by_name }}
                            </span>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </template>
      </div>
    </div>
  </div>
</template>

<script>
import { ref, computed, onMounted } from 'vue'
import { useStore } from 'vuex'
import { useRouter } from 'vue-router'
import axios from 'axios'
import FacultySidebar from '@/components/layout/FacultySidebar.vue'
import TopNav from '@/components/layout/TopNav.vue'
import Swal from 'sweetalert2'

export default {
  name: 'FacultyDashboard',
  components: {
    FacultySidebar,
    TopNav
  },
  setup() {
    const store = useStore()
    const router = useRouter()
    const loading = ref(true)
    const error = ref(null)
    const faculty = ref({})
    const todayClasses = ref([])
    const upcomingEvents = ref([])
    const showDebug = ref(false)
    const refreshing = ref(false)
    const apiResponse = ref(null)
    
    // Get API URL from environment or use default
    const API_URL = import.meta.env.VITE_API_URL || 'http://localhost/ccs-profiling-system/backend/api'

    const currentDate = computed(() => {
      return new Date().toLocaleDateString('en-US', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      })
    })

    const facultyName = computed(() => {
      return faculty.value.name || 
             (faculty.value.first_name && faculty.value.last_name ? 
              faculty.value.first_name + ' ' + faculty.value.last_name : 
              'Professor')
    })

    const debugInfo = computed(() => {
      return {
        loading: loading.value,
        error: error.value,
        faculty: faculty.value,
        todayClasses: todayClasses.value,
        upcomingEvents: upcomingEvents.value,
        token: store.state.auth.token ? 'Present' : 'Missing',
        apiUrl: API_URL,
        apiResponse: apiResponse.value,
        timestamp: new Date().toLocaleString()
      }
    })

    const statistics = computed(() => [
      {
        label: 'Total Classes',
        value: faculty.value.statistics?.total_classes || todayClasses.value.length || 0,
        icon: 'bi bi-calendar-check',
        color: '#3498db'
      },
      {
        label: 'Total Students',
        value: faculty.value.statistics?.total_students || 0,
        icon: 'bi bi-people',
        color: '#27ae60'
      },
      {
        label: 'Subjects',
        value: faculty.value.statistics?.total_subjects || 0,
        icon: 'bi bi-book',
        color: '#f39c12'
      },
      {
        label: 'Upcoming Events',
        value: upcomingEvents.value.length || 0,
        icon: 'bi bi-calendar-event',
        color: '#9b59b6'
      }
    ])

    const fetchDashboardData = async () => {
      loading.value = true
      error.value = null
      
      try {
        const token = store.state.auth.token
        console.log('Fetching dashboard data...')
        console.log('Token:', token ? 'Present' : 'Missing')
        console.log('API URL:', API_URL)
        
        if (!token) {
          console.log('No token found, redirecting to login')
          router.push('/faculty/login')
          return
        }

        const response = await axios.get(`${API_URL}/faculty/dashboard.php`, {
          headers: { 
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
          },
          withCredentials: true,
          timeout: 10000
        })

        console.log('API Response:', response.data)
        apiResponse.value = response.data

        if (response.data.success) {
          faculty.value = response.data.faculty || {}
          faculty.value.statistics = response.data.statistics || {}
          todayClasses.value = response.data.today_classes || []
          upcomingEvents.value = response.data.upcoming_events || []
          console.log('Dashboard data loaded successfully')
          
          // Show success message if events were loaded
          if (upcomingEvents.value.length > 0) {
            Swal.fire({
              icon: 'success',
              title: 'Dashboard Updated',
              text: `Loaded ${upcomingEvents.value.length} upcoming events`,
              timer: 2000,
              showConfirmButton: false,
              toast: true,
              position: 'top-end'
            })
          }
        } else {
          throw new Error(response.data.message || 'Failed to load dashboard data')
        }
      } catch (err) {
        console.error('Dashboard error:', err)
        console.error('Error response:', err.response)
        console.error('Error message:', err.message)
        
        if (err.code === 'ECONNABORTED') {
          error.value = 'Request timeout. Server is taking too long to respond.'
        } else if (err.response) {
          error.value = err.response.data?.message || `Server error: ${err.response.status}`
          
          if (err.response.status === 401) {
            error.value = 'Session expired. Please login again.'
            await store.dispatch('auth/logout')
            setTimeout(() => router.push('/faculty/login'), 2000)
          } else if (err.response.status === 403) {
            error.value = 'Access denied. Faculty privileges required.'
          } else if (err.response.status === 404) {
            error.value = 'Dashboard endpoint not found. Please check API URL.'
          } else if (err.response.status === 500) {
            error.value = 'Server error. Please try again later.'
          }
        } else if (err.request) {
          error.value = 'Cannot connect to server. Please check if XAMPP/WAMP is running.'
        } else {
          error.value = err.message || 'Failed to load dashboard'
        }
        
        // Show sample data for demonstration
        upcomingEvents.value = getSampleEvents()
        todayClasses.value = getSampleClasses()
        
        showDebug.value = true
        
        Swal.fire({
          icon: 'error',
          title: 'Error',
          text: error.value,
          footer: 'Showing sample data for demonstration'
        })
      } finally {
        loading.value = false
      }
    }

    // Sample events for demonstration when API fails
    const getSampleEvents = () => {
      const today = new Date()
      const tomorrow = new Date(today)
      tomorrow.setDate(tomorrow.getDate() + 1)
      
      const nextWeek = new Date(today)
      nextWeek.setDate(nextWeek.getDate() + 7)
      
      const nextMonth = new Date(today)
      nextMonth.setMonth(nextMonth.getMonth() + 1)
      
      return [
        {
          id: 1,
          title: 'Faculty Meeting',
          description: 'Monthly faculty meeting to discuss curriculum updates',
          event_type: 'Curricular',
          event_date: tomorrow.toISOString().split('T')[0],
          event_time: '10:00:00',
          venue: 'Conference Room A',
          organizer: 'Dean\'s Office',
          created_by_name: 'System'
        },
        {
          id: 2,
          title: 'Department Workshop',
          description: 'Workshop on new teaching methodologies',
          event_type: 'Curricular',
          event_date: nextWeek.toISOString().split('T')[0],
          event_time: '14:00:00',
          venue: 'Computer Lab 101',
          organizer: 'CS Department',
          created_by_name: 'System'
        },
        {
          id: 3,
          title: 'University Foundation Day',
          description: 'Celebration of university founding anniversary',
          event_type: 'Extracurricular',
          event_date: nextMonth.toISOString().split('T')[0],
          event_time: '09:00:00',
          venue: 'University Gymnasium',
          organizer: 'University Events Office',
          created_by_name: 'System'
        }
      ]
    }

    // Sample classes for demonstration when API fails
    const getSampleClasses = () => {
      return [
        {
          id: 1,
          course_code: 'CS101',
          course_name: 'Introduction to Programming',
          section_code: 'A',
          room_code: 'Room 101',
          time_start: '09:00:00',
          time_end: '10:30:00',
          student_count: 25
        },
        {
          id: 2,
          course_code: 'CS102',
          course_name: 'Data Structures',
          section_code: 'B',
          room_code: 'Room 102',
          time_start: '13:00:00',
          time_end: '14:30:00',
          student_count: 30
        }
      ]
    }

    const formatTime = (time) => {
      if (!time) return '--:--'
      try {
        return new Date('1970-01-01T' + time).toLocaleTimeString('en-US', {
          hour: 'numeric',
          minute: '2-digit',
          hour12: true
        })
      } catch {
        return time
      }
    }

    const formatEventMonth = (dateString) => {
      if (!dateString) return ''
      try {
        const date = new Date(dateString)
        return date.toLocaleDateString('en-US', { month: 'short' })
      } catch {
        return ''
      }
    }

    const formatEventDay = (dateString) => {
      if (!dateString) return ''
      try {
        const date = new Date(dateString)
        return date.getDate()
      } catch {
        return ''
      }
    }

    const formatEventTime = (timeString) => {
      if (!timeString) return ''
      try {
        return new Date('1970-01-01T' + timeString).toLocaleTimeString('en-US', {
          hour: 'numeric',
          minute: '2-digit',
          hour12: true
        })
      } catch {
        return timeString
      }
    }

    const getEventTypeClass = (type) => {
      const types = {
        'Curricular': 'bg-primary',
        'Extracurricular': 'bg-success'
      }
      return types[type] || 'bg-info'
    }

    const getDaysRemaining = (dateString) => {
      if (!dateString) return ''
      
      try {
        const eventDate = new Date(dateString)
        const today = new Date()
        today.setHours(0, 0, 0, 0)
        eventDate.setHours(0, 0, 0, 0)
        
        const diffTime = eventDate - today
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))
        
        if (diffDays === 0) return 'Today'
        if (diffDays === 1) return 'Tomorrow'
        if (diffDays < 0) return 'Past event'
        return `${diffDays} days left`
      } catch {
        return ''
      }
    }

    const getDaysRemainingClass = (dateString) => {
      if (!dateString) return 'bg-secondary'
      
      try {
        const eventDate = new Date(dateString)
        const today = new Date()
        today.setHours(0, 0, 0, 0)
        eventDate.setHours(0, 0, 0, 0)
        
        const diffDays = Math.ceil((eventDate - today) / (1000 * 60 * 60 * 24))
        
        if (diffDays <= 0) return 'bg-secondary'
        if (diffDays <= 3) return 'bg-warning'
        if (diffDays <= 7) return 'bg-info'
        return 'bg-success'
      } catch {
        return 'bg-secondary'
      }
    }

    const getClassStatus = (start, end) => {
      if (!start || !end) return 'bg-secondary'
      
      try {
        const now = new Date()
        const currentTime = now.getHours() * 60 + now.getMinutes()
        
        const startTime = new Date('1970-01-01T' + start)
        const endTime = new Date('1970-01-01T' + end)
        const startMinutes = startTime.getHours() * 60 + startTime.getMinutes()
        const endMinutes = endTime.getHours() * 60 + endTime.getMinutes()
        
        if (currentTime < startMinutes) return 'bg-warning'
        if (currentTime > endMinutes) return 'bg-secondary'
        return 'bg-success'
      } catch {
        return 'bg-secondary'
      }
    }

    const getClassStatusText = (start, end) => {
      if (!start || !end) return 'Unknown'
      
      try {
        const now = new Date()
        const currentTime = now.getHours() * 60 + now.getMinutes()
        
        const startTime = new Date('1970-01-01T' + start)
        const endTime = new Date('1970-01-01T' + end)
        const startMinutes = startTime.getHours() * 60 + startTime.getMinutes()
        const endMinutes = endTime.getHours() * 60 + endTime.getMinutes()
        
        if (currentTime < startMinutes) return 'Upcoming'
        if (currentTime > endMinutes) return 'Completed'
        return 'Ongoing'
      } catch {
        return 'Unknown'
      }
    }

    const refreshData = async () => {
      refreshing.value = true
      await fetchDashboardData()
      refreshing.value = false
    }

    const testApiConnection = async () => {
      try {
        const result = await Swal.fire({
          title: 'Testing API Connection',
          html: 'Connecting to:<br>' + API_URL,
          icon: 'info',
          showCancelButton: true,
          confirmButtonText: 'Test',
          cancelButtonText: 'Cancel'
        })
        
        if (result.isConfirmed) {
          const token = store.state.auth.token
          const response = await axios.get(`${API_URL}/test.php`, {
            headers: { 'Authorization': `Bearer ${token}` },
            timeout: 5000
          })
          console.log('Test API response:', response.data)
          
          Swal.fire({
            icon: 'success',
            title: 'Connection Successful!',
            html: `<pre>${JSON.stringify(response.data, null, 2)}</pre>`,
            confirmButtonText: 'OK'
          })
        }
      } catch (err) {
        console.error('Test API error:', err)
        Swal.fire({
          icon: 'error',
          title: 'Connection Failed',
          text: err.message,
          footer: 'Make sure XAMPP/WAMP is running'
        })
      }
    }

    onMounted(() => {
      console.log('Component mounted')
      console.log('Store auth state:', store.state.auth)
      fetchDashboardData()
    })

    return {
      loading,
      error,
      faculty,
      facultyName,
      statistics,
      todayClasses,
      upcomingEvents,
      currentDate,
      showDebug,
      debugInfo,
      refreshing,
      formatTime,
      formatEventMonth,
      formatEventDay,
      formatEventTime,
      getEventTypeClass,
      getDaysRemaining,
      getDaysRemainingClass,
      getClassStatus,
      getClassStatusText,
      refreshData,
      testApiConnection,
      fetchDashboardData
    }
  }
}
</script>

<style scoped>
/* Same styles as before - keeping your existing styles */
.app-wrapper {
  display: flex;
  min-height: 100vh;
  background-color: #f8f9fa;
}

.main-content {
  flex: 1;
  margin-left: 280px;
  transition: margin-left 0.3s ease;
  width: calc(100% - 280px);
}

/* Welcome Banner */
.welcome-banner {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  padding: 2rem;
  border-radius: 15px;
  box-shadow: 0 10px 30px rgba(102, 126, 234, 0.3);
}

.avatar-circle {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.8rem;
  font-weight: 600;
  background: rgba(255, 255, 255, 0.2);
  border: 3px solid rgba(255, 255, 255, 0.5);
}

.date-badge {
  background: rgba(255, 255, 255, 0.2);
  padding: 0.5rem 1rem;
  border-radius: 50px;
  backdrop-filter: blur(10px);
  font-size: 0.9rem;
}

.text-white-50 {
  color: rgba(255, 255, 255, 0.7) !important;
}

/* Statistics Cards */
.stat-card {
  background: white;
  border-radius: 15px;
  padding: 1.5rem;
